import { useState } from "react";
import Button from "../components/Button";

const USERS_STORAGE_KEY = "ecommerce_demo_users";
const ACTIVE_USER_STORAGE_KEY = "ecommerce_demo_user";

const seedUsers = [
  {
    name: "Oliver Stone",
    email: "demo@novacart.com",
    password: "demo1234",
  },
];

const demoOrderHistory = [
  {
    id: "ORD-13284",
    date: "Feb 20, 2026",
    status: "Delivered",
    total: "$149.99",
  },
  {
    id: "ORD-12910",
    date: "Jan 11, 2026",
    status: "Shipped",
    total: "$89.99",
  },
];

function readUsersFromStorage() {
  const storedUsers = localStorage.getItem(USERS_STORAGE_KEY);
  if (!storedUsers) {
    localStorage.setItem(USERS_STORAGE_KEY, JSON.stringify(seedUsers));
    return seedUsers;
  }
  try {
    return JSON.parse(storedUsers);
  } catch {
    localStorage.setItem(USERS_STORAGE_KEY, JSON.stringify(seedUsers));
    return seedUsers;
  }
}

function LoginPage() {
  const [users, setUsers] = useState(() => readUsersFromStorage());
  const [activeUser, setActiveUser] = useState(() => {
    const storedUser = localStorage.getItem(ACTIVE_USER_STORAGE_KEY);
    return storedUser ? JSON.parse(storedUser) : null;
  });
  const [authMode, setAuthMode] = useState("signin");
  const [authError, setAuthError] = useState("");

  const [signInData, setSignInData] = useState({
    email: "",
    password: "",
    rememberMe: true,
  });
  const [registerData, setRegisterData] = useState({
    name: "",
    email: "",
    password: "",
  });

  const handleSignIn = (event) => {
    event.preventDefault();
    setAuthError("");

    const user = users.find(
      (entry) =>
        entry.email.toLowerCase() === signInData.email.trim().toLowerCase() &&
        entry.password === signInData.password
    );

    if (!user) {
      setAuthError("Invalid email or password.");
      return;
    }

    const authenticatedUser = { name: user.name, email: user.email };
    setActiveUser(authenticatedUser);

    if (signInData.rememberMe) {
      localStorage.setItem(
        ACTIVE_USER_STORAGE_KEY,
        JSON.stringify(authenticatedUser)
      );
    } else {
      localStorage.removeItem(ACTIVE_USER_STORAGE_KEY);
    }
  };

  const handleRegister = (event) => {
    event.preventDefault();
    setAuthError("");

    const alreadyExists = users.some(
      (entry) =>
        entry.email.toLowerCase() === registerData.email.trim().toLowerCase()
    );

    if (alreadyExists) {
      setAuthError("An account already exists with this email. Please sign in.");
      setAuthMode("signin");
      setSignInData((current) => ({
        ...current,
        email: registerData.email.trim(),
        password: "",
      }));
      return;
    }

    const newUser = {
      name: registerData.name.trim(),
      email: registerData.email.trim().toLowerCase(),
      password: registerData.password,
    };

    const updatedUsers = [...users, newUser];
    setUsers(updatedUsers);
    localStorage.setItem(USERS_STORAGE_KEY, JSON.stringify(updatedUsers));

    setAuthMode("signin");
    setSignInData((current) => ({
      ...current,
      email: newUser.email,
      password: newUser.password,
    }));
    setAuthError("Account created. You can sign in now.");
  };

  const handleLogout = () => {
    setActiveUser(null);
    localStorage.removeItem(ACTIVE_USER_STORAGE_KEY);
  };

  return (
    <div className="mx-auto max-w-7xl px-4 py-8 sm:px-6 lg:px-8">
      <h1 className="mb-6 text-2xl font-bold text-slate-900">Login & Profile</h1>

      <div className="grid gap-6 lg:grid-cols-2">
        <section className="rounded-xl border border-slate-100 bg-white p-6 shadow-md">
          {!activeUser ? (
            <>
              <div className="mb-5 flex items-center justify-between">
                <h2 className="text-xl font-bold text-slate-900">
                  {authMode === "signin" ? "Sign In" : "Create Account"}
                </h2>
                <button
                  className="text-sm font-semibold text-primary-600"
                  onClick={() =>
                    setAuthMode((current) =>
                      current === "signin" ? "signup" : "signin"
                    )
                  }
                  type="button"
                >
                  {authMode === "signin"
                    ? "New user? Sign up"
                    : "Already have account? Sign in"}
                </button>
              </div>

              <p className="mb-4 text-sm text-slate-500">
                {authMode === "signin"
                  ? "Already have an account? Enter your email and password to login directly."
                  : "Create your account in a few seconds."}
              </p>

              {authError ? (
                <p className="mb-4 rounded-lg bg-primary-50 px-3 py-2 text-sm text-primary-700">
                  {authError}
                </p>
              ) : null}

              {authMode === "signin" ? (
                <form className="space-y-4" onSubmit={handleSignIn}>
                  <InputField
                    label="Email"
                    onChange={(event) =>
                      setSignInData((current) => ({
                        ...current,
                        email: event.target.value,
                      }))
                    }
                    type="email"
                    value={signInData.email}
                  />
                  <InputField
                    label="Password"
                    onChange={(event) =>
                      setSignInData((current) => ({
                        ...current,
                        password: event.target.value,
                      }))
                    }
                    type="password"
                    value={signInData.password}
                  />

                  <label className="flex items-center gap-2 text-sm text-slate-600">
                    <input
                      checked={signInData.rememberMe}
                      className="h-4 w-4 rounded border-slate-300 text-primary-600 focus:ring-primary-500"
                      onChange={(event) =>
                        setSignInData((current) => ({
                          ...current,
                          rememberMe: event.target.checked,
                        }))
                      }
                      type="checkbox"
                    />
                    Remember me
                  </label>

                  <Button className="w-full" type="submit" variant="primary">
                    Sign In
                  </Button>
                </form>
              ) : (
                <form className="space-y-4" onSubmit={handleRegister}>
                  <InputField
                    label="Full Name"
                    onChange={(event) =>
                      setRegisterData((current) => ({
                        ...current,
                        name: event.target.value,
                      }))
                    }
                    value={registerData.name}
                  />
                  <InputField
                    label="Email"
                    onChange={(event) =>
                      setRegisterData((current) => ({
                        ...current,
                        email: event.target.value,
                      }))
                    }
                    type="email"
                    value={registerData.email}
                  />
                  <InputField
                    label="Password"
                    onChange={(event) =>
                      setRegisterData((current) => ({
                        ...current,
                        password: event.target.value,
                      }))
                    }
                    type="password"
                    value={registerData.password}
                  />
                  <Button className="w-full" type="submit" variant="primary">
                    Create Account
                  </Button>
                </form>
              )}

              <div className="mt-6 rounded-xl border border-dashed border-slate-200 p-4 text-xs text-slate-500">
                Demo account: <strong>demo@novacart.com</strong> /{" "}
                <strong>demo1234</strong>
              </div>
            </>
          ) : (
            <>
              <h2 className="text-xl font-bold text-slate-900">Signed In</h2>
              <div className="mt-4 rounded-xl bg-primary-50 p-4">
                <p className="text-sm font-semibold text-primary-700">{activeUser.name}</p>
                <p className="mt-1 text-sm text-slate-600">{activeUser.email}</p>
              </div>
              <Button className="mt-5" onClick={handleLogout} variant="secondary">
                Logout
              </Button>
            </>
          )}
        </section>

        <section className="rounded-xl border border-slate-100 bg-white p-6 shadow-md">
          <h2 className="text-xl font-bold text-slate-900">My Account</h2>
          {activeUser ? (
            <div className="mt-5 space-y-5">
              <div>
                <h3 className="text-sm font-semibold uppercase tracking-wide text-slate-500">
                  Order History
                </h3>
                <div className="mt-3 space-y-3">
                  {demoOrderHistory.map((order) => (
                    <div
                      className="rounded-xl border border-slate-100 p-3"
                      key={order.id}
                    >
                      <div className="flex items-center justify-between text-sm">
                        <p className="font-semibold text-slate-800">{order.id}</p>
                        <p className="text-slate-500">{order.date}</p>
                      </div>
                      <div className="mt-2 flex items-center justify-between text-sm">
                        <p className="text-slate-600">{order.status}</p>
                        <p className="font-bold text-slate-900">{order.total}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>

              <div>
                <h3 className="text-sm font-semibold uppercase tracking-wide text-slate-500">
                  Account Details
                </h3>
                <div className="mt-3 rounded-xl border border-slate-100 p-4 text-sm text-slate-600">
                  <p>Shipping Preference: Standard Delivery</p>
                  <p className="mt-2">Saved Address: 223 Market Street, Seattle</p>
                </div>
              </div>
            </div>
          ) : (
            <div className="mt-5 rounded-xl border border-dashed border-slate-200 p-6 text-sm text-slate-500">
              Sign in to view order history and account details.
            </div>
          )}
        </section>
      </div>
    </div>
  );
}

function InputField({ label, onChange, type = "text", value }) {
  return (
    <label className="block">
      <span className="mb-1 block text-sm font-medium text-slate-700">{label}</span>
      <input
        className="w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-700 focus:border-primary-500 focus:outline-none"
        onChange={onChange}
        required
        type={type}
        value={value}
      />
    </label>
  );
}

export default LoginPage;
